body.script:
window.addEventListener("DOMContentLiteSpeedLoaded",function(){jQuery(document).on("elementor/popup/show",function(){setTimeout(()=>{document.querySelectorAll(".wpcf7-form").forEach(function(form){if(typeof wpcf7!=="undefined"){wpcf7.init(form)}
function injectRecaptchaToken(targetForm){if(typeof grecaptcha!=="undefined"&&typeof grecaptcha.execute==="function"){grecaptcha.ready(function(){grecaptcha.execute("6LeL_M4pAAAAANWH5NyfON60mO9jmFYPm1cakW2E",{action:"wpcf7",}).then(function(token){let inputs=targetForm.querySelectorAll('input[name="_wpcf7_recaptcha_response"]');if(inputs.length===0){const hidden=document.createElement("input");hidden.type="hidden";hidden.name="_wpcf7_recaptcha_response";hidden.value=token;targetForm.appendChild(hidden)}else{inputs.forEach(function(el){el.value=token})}
targetForm.dispatchEvent(new Event("wpcf7grecaptchaexecuted"));console.log("New token injected:",token)})})}}
injectRecaptchaToken(form);form.addEventListener("wpcf7reset",function(){console.log("Form reset, regenerating token...");injectRecaptchaToken(form)})})},500)})})

div.script:
jQuery(document).ready(function($){console.log("Blocking URLs in Name and Textarea Fields");const form=$('#support_form');const fullNameField=$('input[name="form_fields[name]"]');const companyField=$('input[name="form_fields[company]"]');let nameValid=!1;let companyValid=!1;function validateField(field,errorClass,fieldLabel){let value=field.val().trim();let errorContainer=field.siblings(errorClass);if(errorContainer.length===0){field.after(`
`);errorContainer=field.siblings(errorClass)}
if(/www/i.test(value)){errorContainer.text(`Invalid input: Please remove "www" from the ${fieldLabel} field.`);field.css('border','1px solid red');return!1}else if(/[^a-zA-Z\s]/.test(value)){errorContainer.text(`Invalid input: Only letters and spaces are allowed in ${fieldLabel}.`);field.css('border','1px solid red');return!1}else if(value===''){errorContainer.text(`${fieldLabel} is required.`);field.css('border','1px solid red');return!1}else{errorContainer.text('');field.css('border','1px solid #ccc');return!0}}
fullNameField.on('input',function(){nameValid=validateField(fullNameField,'.name-error','Full Name')});companyField.on('input',function(){companyValid=validateField(companyField,'.company-error','Company')});form.on('submit',function(e){nameValid=validateField(fullNameField,'.name-error','Full Name');companyValid=validateField(companyField,'.company-error','Company');if(!nameValid||!companyValid){e.preventDefault();e.stopImmediatePropagation();alert('Please fix the errors before submitting the form.')}})})
